mapper.select:
select * from bus_schedule

    
        and schedule_name like concat('%', #{query.scheduleName}, '%')
    
    
        and status = #{query.status}
    
    
        AND DATE(depart_time) >= #{query.departTime}
    
    
    
        AND DATE(depart_time) <= #{query.arriveTime}
    
    and create_user = #{userId}

ORDER BY create_time DESC

        SELECT COUNT(schedule_id)
        FROM bus_schedule
        LEFT JOIN line ON bus_schedule.line_id = line.line_id
        
            
                and bus_schedule.schedule_name like concat('%', #{query.scheduleName}, '%')
            
            
                and bus_schedule.status = #{query.status}
            

            and bus_schedule.create_user = #{userId}

SELECT t.*, line.start_city, line.end_city, station.station_id, station.station_name, station.lng, station.lat, station.address FROM ( SELECT DISTINCT bs.* FROM bus_schedule bs LEFT JOIN line l ON bs.line_id = l.line_id
AND bs.schedule_name LIKE CONCAT('%', #{query.scheduleName}, '%')
AND bs.status = #{query.status}
AND DATE(bs.depart_time) >= #{query.departTime}
AND DATE(bs.depart_time) <= #{query.arriveTime}
AND bs.create_user = #{userId}
ORDER BY bs.depart_time DESC, bs.schedule_id DESC LIMIT #{pageStart}, #{query.pageSize} ) t
LEFT JOIN line ON t.line_id = line.line_id LEFT JOIN JSON_TABLE( line.station_list, '$[*]' COLUMNS ( station_id INT PATH '$', idx FOR ORDINALITY ) ) jt ON TRUE LEFT JOIN station ON jt.station_id = station.station_id
ORDER BY t.depart_time DESC, t.schedule_id DESC, jt.idx

mapper.update:
UPDATE bus_schedule
SET seat_remaining = seat_remaining - #{ticketCount}
WHERE schedule_id = #{scheduleId}
AND seat_remaining >= #{ticketCount}

UPDATE bus_schedule
SET seat_remaining = seat_remaining + #{ticketCount}
WHERE schedule_id = #{scheduleId}

